import test from 'node:test';
import assert from 'node:assert/strict';

import { CookieJar } from '../src/cookie-jar.mjs';
import { formatCookieHeader } from '../src/cookie-header.mjs';

test('scoping, transport policy, and deletion compose for a domain cookie', () => {
  const jar = new CookieJar();
  jar.store(
    'sid=live; Domain=.example.test; Path=/app; Secure',
    'https://api.example.test/app/login',
    1000
  );
  assert.equal(
    formatCookieHeader(jar.cookiesFor('https://edge.example.test/app/jobs', 1000)),
    'sid=live'
  );
  assert.equal(formatCookieHeader(jar.cookiesFor('https://edge.example.test/appetite', 1000)), '');
  assert.equal(formatCookieHeader(jar.cookiesFor('http://edge.example.test/app/jobs', 1000)), '');
  assert.equal(formatCookieHeader(jar.cookiesFor('https://notexample.test/app/jobs', 1000)), '');

  jar.store(
    'sid=deleted; Domain=.example.test; Path=/app; Secure; Max-Age=0',
    'https://api.example.test/app/login',
    1000
  );
  assert.equal(formatCookieHeader(jar.cookiesFor('https://edge.example.test/app/jobs', 1000)), '');
});
